#include <bits/stdc++.h>
using namespace std;
int main(){
    long long a;
    cin>>a;
    long long f[1000001];
    for(int i=1;i<=a;i++){
        f[i]=1e9;
    }
    f[0]=0;
    for(int i=1;i<=a;i++){
        f[i]=f[i-1]+1;
        if(i>=5){
            f[i]=min(f[i],f[i-5]+1);
        }
        if(i>=11){
            f[i]=min(f[i],f[i-11]+1);
        }
    }
    cout<<f[a];
    return 0;
}
